import axios from 'axios';

const API_BASE_URL = 'http://localhost:5001'; // Trỏ về Server Admin

class OrderService {
    // Lấy danh sách toàn bộ đơn hàng
    async getAllOrders() {
        const token = localStorage.getItem("token");
        const res = await axios.get(`${API_BASE_URL}/admin/orders`, {
            headers: { Authorization: `Bearer ${token}` }
        });
        return res.data;
    }

    // Lấy chi tiết một đơn hàng
    async getOrderDetail(id) {
        const token = localStorage.getItem("token");
        const res = await axios.get(`${API_BASE_URL}/admin/orders/${id}`, {
            headers: { Authorization: `Bearer ${token}` }
        });
        return res.data;
    }

    // Cập nhật trạng thái đơn hàng
    async updateOrderStatus(id, status) {
        const token = localStorage.getItem("token");
        const res = await axios.put(`${API_BASE_URL}/admin/orders/${id}`, 
            { status }, // Body chứa trạng thái mới
            { headers: { Authorization: `Bearer ${token}` } }
        );
        return res.data;
    }
}

export default new OrderService();
